const extractData = $input.first().json;
const doc = extractData.data || extractData;

const triggerData = $('New Customs Doc').item.json;
const fileName = triggerData.name || 'unknown';
const fileId   = triggerData.id   || '';

const docType    = doc.documentType   || 'Unknown';
const docNumber  = doc.documentNumber || 'N/A';
const shipmentId = doc.shipmentId     || docNumber;

const shipperName    = doc.shipperName    || 'Unknown';
const consigneeName  = doc.consigneeName  || 'Unknown';
const declaredValue  = parseFloat(doc.declaredValue)  || 0;
const calculatedValue= parseFloat(doc.calculatedValue)|| 0;
const declaredWeight = parseFloat(doc.declaredWeight) || 0;

const discrepancies = [];
let validationStatus = 'Valid';

// Value check — allow 1% tolerance
if (calculatedValue > 0 && declaredValue > 0) {
  const valueDiff = Math.abs(declaredValue - calculatedValue);
  if (valueDiff / calculatedValue > 0.01) {
    discrepancies.push(
      `Value mismatch: declared $${declaredValue} vs calculated $${calculatedValue}`
    );
  }
}

// Required fields
if (!doc.hsCodes)           discrepancies.push('Missing HS codes');
if (!doc.countryOfOrigin)   discrepancies.push('Missing country of origin');
if (!doc.goodsDescription)  discrepancies.push('Missing goods description');
if (!doc.portOfLoading)     discrepancies.push('Missing port of loading');
if (!doc.portOfDischarge)   discrepancies.push('Missing port of discharge');
if (declaredValue <= 0)     discrepancies.push('Missing or zero declared value');
if (declaredWeight <= 0)    discrepancies.push('Missing declared weight');

// Hazmat flag
if (doc.hazmatPresent) discrepancies.push('Hazmat goods — additional documentation required');

if (discrepancies.length >= 3)      validationStatus = 'Failed';
else if (discrepancies.length > 0)  validationStatus = 'Review Required';

return [{ json: {
  shipmentId,
  documentType:     docType,
  documentNumber:   docNumber,
  documentDate:     doc.documentDate    || 'N/A',
  shipperName,
  shipperCountry:   doc.shipperCountry  || 'N/A',
  consigneeName,
  consigneeCountry: doc.consigneeCountry|| 'N/A',
  originCountry:    doc.countryOfOrigin || doc.originCountry || 'N/A',
  destination:      doc.destinationCountry || 'N/A',
  portOfLoading:    doc.portOfLoading   || 'N/A',
  portOfDischarge:  doc.portOfDischarge || 'N/A',
  carrier:          doc.carrier         || 'N/A',
  declaredValue,
  calculatedValue,
  declaredWeight,
  weightUnit:       doc.weightUnit      || 'kg',
  packageCount:     doc.packageCount    || 0,
  hsCodes:          doc.hsCodes         || 'N/A',
  goodsDescription: doc.goodsDescription|| 'N/A',
  lineItemsSummary: doc.lineItemsSummary|| 'N/A',
  incoterms:        doc.incoterms       || 'N/A',
  containerNumbers: doc.containerNumbers|| 'N/A',
  hazmatPresent:    doc.hazmatPresent   ? 'Yes' : 'No',
  validationStatus,
  discrepancies:    discrepancies.join('; ') || 'None',
  discrepancyCount: discrepancies.length,
  fileName,
  fileId,
  processedAt: new Date().toISOString()
}}];

